def execute(params):
    """Delete a directory and all its contents recursively."""
    import shutil
    import os

    dir_path = params.get('dirPath')
    if not dir_path:
        return {'success': False, 'error': 'dirPath parameter is required'}

    try:
        if os.path.isfile(dir_path):
            return {'success': False, 'error': f'Path is a file, not a directory. Use delete_file instead: {dir_path}'}

        if not os.path.exists(dir_path):
            return {'success': False, 'error': f'Directory not found: {dir_path}'}

        shutil.rmtree(dir_path)
        return {
            'success': True,
            'message': f'Directory deleted: {dir_path}'
        }
    except Exception as e:
        return {'success': False, 'error': str(e)}

def execute(params):
    """List all files and directories in a path."""
    import os

    dir_path = params.get('dirPath')
    if not dir_path:
        return {'success': False, 'error': 'dirPath parameter is required'}

    recursive = params.get('recursive', False)

    try:
        if recursive:
            files = []
            for root, dirs, filenames in os.walk(dir_path):
                for filename in filenames:
                    files.append(os.path.join(root, filename))
        else:
            files = os.listdir(dir_path)

        return {
            'success': True,
            'files': files,
            'count': len(files)
        }
    except Exception as e:
        return {'success': False, 'error': str(e)}

