def execute(params):
    """Extract a ZIP archive."""
    import zipfile
    import os

    zip_path = params.get('zipPath')
    extract_path = params.get('extractPath')

    if not zip_path:
        return {'success': False, 'error': 'zipPath parameter is required'}

    if not extract_path:
