            'success': True,
            'message': f'Screenshot saved to {save_path}',
            'savePath': save_path
        }
    except ImportError:
        return {'success': False, 'error': 'mss module not installed. Install with: pip install mss'}
    except Exception as e:
        return {'success': False, 'error': str(e)}

def execute(params):
    """Convert image format."""
    input_path = params.get('inputPath')
    output_path = params.get('outputPath')

    if not input_path or not output_path:
        return {'success': False, 'error': 'inputPath and outputPath parameters are required'}

    format_param = params.get('format', '').upper()

    try:
        from PIL import Image

        img = Image.open(input_path)

        if format_param:
            img.save(output_path, format=format_param)
        else:
            img.save(output_path)

        return {
            'success': True,
            'message': f'Image converted: {input_path} -> {output_path}',
            'inputPath': input_path,
            'outputPath': output_path,
            'format': format_param if format_param else 'auto'
        }
    except ImportError:
        return {'success': False, 'error': 'PIL (Pillow) not installed. Install with: pip install pillow'}
    except Exception as e:
        return {'success': False, 'error': str(e)}

def execute(params):
    """List running processes."""
    import platform
    import subprocess

    sort_by = params.get('sort_by', 'pid')
    limit = params.get('limit', 50)
    system = platform.system().lower()
    processes = []

    try:
        if system == 'windows':
            cmd = 'tasklist /fo csv /nh'
            result = subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=30)
            lines = result.stdout.strip().split('\n')
            for line in lines:
                if line.strip():
                    parts = line.strip().split('","')
                    if len(parts) >= 5:
                        name = parts[0].strip('"')
                        pid = parts[1].strip('"')
                        mem = parts[4].strip('"').replace(' K', '').replace(',', '')
                        try:
                            processes.append({'pid': int(pid), 'name': name, 'cpu_percent': 0.0, 'memory_mb': int(mem) / 1024 if mem.isdigit() else 0})
                        except ValueError:
                            pass
        else:
            cmd = 'ps aux --no-headers' if system == 'linux' else 'ps aux'
            result = subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=30)
            lines = result.stdout.strip().split('\n')
            start_idx = 1 if system == 'darwin' else 0
            for line in lines[start_idx:]:
                if line.strip():
                    parts = line.split()
                    if len(parts) >= 11:
                        try:
                            processes.append({'pid': int(parts[1]), 'name': parts[10], 'cpu_percent': float(parts[2]), 'memory_mb': int(parts[5]) / 1024})
                        except (ValueError, IndexError):
                            pass

        sort_key = sort_by.lower()
        if sort_key == 'cpu':
            processes.sort(key=lambda x: x['cpu_percent'], reverse=True)
        elif sort_key in ('memory', 'mem'):
            processes.sort(key=lambda x: x['memory_mb'], reverse=True)
        elif sort_key == 'name':
            processes.sort(key=lambda x: x['name'].lower())
        else:
            processes.sort(key=lambda x: x['pid'])

        if limit and limit > 0:
            processes = processes[:int(limit)]

        return {'success': True, 'platform': system, 'count': len(processes), 'processes': processes}
    except Exception as e:
        return {'success': False, 'error': str(e)}

def execute(params):
    """Kill a process by PID or name."""
    import platform
    import subprocess
    import os
    import signal

    pid = params.get('pid')
    name = params.get('name')

    if not pid and not name:
        return {'success': False, 'error': 'Either pid or name parameter is required'}

    system = platform.system().lower()
    killed = []

    try:
        if pid:
            pid = int(pid)
            if system == 'windows':
                result = subprocess.run(f'taskkill /PID {pid} /F', shell=True, capture_output=True, text=True, timeout=10)
                if result.returncode == 0:
                    killed.append({'pid': pid})
                else:
                    return {'success': False, 'error': result.stderr.strip()}
            else:
                os.kill(pid, signal.SIGTERM)
                killed.append({'pid': pid})

        if name:
            if system == 'windows':
                result = subprocess.run(f'taskkill /IM "{name}" /F', shell=True, capture_output=True, text=True, timeout=10)
                if result.returncode == 0:
                    killed.append({'name': name})
            else:
                result = subprocess.run(f'pkill -f "{name}"', shell=True, capture_output=True, text=True, timeout=10)
                if result.returncode == 0:
                    killed.append({'name': name})

        return {'success': True, 'killed': killed} if killed else {'success': False, 'error': 'No processes killed'}
    except Exception as e:
        return {'success': False, 'error': str(e)}

def execute(params):
