    system = platform.system().lower()
    full_cmd = [command] + [str(a) for a in args] if args else [command]

    try:
        if system == 'windows':
            process = subprocess.Popen(full_cmd, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, stdin=subprocess.DEVNULL, creationflags=0x00000008)
        else:
            process = subprocess.Popen(full_cmd, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, stdin=subprocess.DEVNULL, start_new_session=True)

        return {'success': True, 'pid': process.pid, 'command': command, 'args': args}
    except FileNotFoundError:
        return {'success': False, 'error': f'Command not found: {command}'}
    except Exception as e:
        return {'success': False, 'error': str(e)}

