def execute(params):
    """Get git repository status."""
    import subprocess
    import os

    repo_path = params.get('repoPath', os.getcwd())

    try:
        result = subprocess.run(
            ['git', 'status', '--porcelain', '-b'],
            capture_output=True,
            text=True,
            cwd=repo_path,
            timeout=30
        )

        if result.returncode != 0:
            return {'success': False, 'error': result.stderr.strip()}

        lines = result.stdout.strip().split('\n')
        branch = lines[0][3:] if lines and lines[0].startswith('##') else 'unknown'

        files = {'modified': [], 'staged': [], 'untracked': []}
        for line in lines[1:]:
            if line:
                status = line[:2]
                filename = line[3:]
                if status[0] in 'MADRC':
                    files['staged'].append(filename)
                if status[1] in 'MD':
                    files['modified'].append(filename)
                if status == '??':
                    files['untracked'].append(filename)

        return {
            'success': True,
            'branch': branch,
            'files': files,
            'raw': result.stdout
        }
    except Exception as e:
        return {'success': False, 'error': str(e)}

