def execute(params):
    """Get git commit history."""
    import subprocess
    import os

    repo_path = params.get('repoPath', os.getcwd())
    limit = params.get('limit', 10)
    oneline = params.get('oneline', True)

    try:
        cmd = ['git', 'log', f'-{limit}']
        if oneline:
            cmd.append('--oneline')
        else:
            cmd.append('--pretty=format:%H|%an|%ad|%s')

        result = subprocess.run(
            cmd,
            capture_output=True,
            text=True,
            cwd=repo_path,
            timeout=30
        )

        if result.returncode != 0:
            return {'success': False, 'error': result.stderr.strip()}

        commits = []
        for line in result.stdout.strip().split('\n'):
            if line:
                if oneline:
                    parts = line.split(' ', 1)
                    commits.append({'hash': parts[0], 'message': parts[1] if len(parts) > 1 else ''})
                else:
                    parts = line.split('|')
                    if len(parts) >= 4:
                        commits.append({'hash': parts[0], 'author': parts[1], 'date': parts[2], 'message': parts[3]})

        return {
            'success': True,
            'commits': commits,
            'count': len(commits)
        }
    except Exception as e:
        return {'success': False, 'error': str(e)}

