def execute(params):
    """Get system uptime."""
    import platform
    import subprocess

    system = platform.system().lower()

    try:
        if system == 'linux':
            with open('/proc/uptime', 'r') as f:
                uptime_seconds = float(f.readline().split()[0])
        elif system == 'darwin':
            result = subprocess.run(['sysctl', '-n', 'kern.boottime'], capture_output=True, text=True)
            import re
            match = re.search(r'sec = (\d+)', result.stdout)
            if match:
                import time
                boot_time = int(match.group(1))
                uptime_seconds = time.time() - boot_time
            else:
                return {'success': False, 'error': 'Could not parse boot time'}
        elif system == 'windows':
            result = subprocess.run(['wmic', 'os', 'get', 'lastbootuptime'], capture_output=True, text=True)
            lines = result.stdout.strip().split('\n')
            if len(lines) > 1:
                boot_str = lines[1].strip()[:14]
                from datetime import datetime
                import time
                boot_time = datetime.strptime(boot_str, '%Y%m%d%H%M%S')
                uptime_seconds = (datetime.now() - boot_time).total_seconds()
            else:
                return {'success': False, 'error': 'Could not get boot time'}
        else:
            return {'success': False, 'error': f'Unsupported platform: {system}'}

        days = int(uptime_seconds // 86400)
        hours = int((uptime_seconds % 86400) // 3600)
        minutes = int((uptime_seconds % 3600) // 60)

        return {
            'success': True,
            'uptime_seconds': uptime_seconds,
            'uptime_string': f'{days}d {hours}h {minutes}m',
            'platform': system
        }
    except Exception as e:
        return {'success': False, 'error': str(e)}

